def find_max(arr):
    max_val = arr[0]
    for x in arr:          # Visits every element — O(n)
        if x > max_val:
            max_val = x
    return max_val

def bubble_sort(arr):
    n = len(arr)
    for i in range(n):          # Outer loop — O(n)
        for j in range(n - 1): # Inner loop — O(n)
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
# Total: O(n²)

def fibonacci(n):
    if n <= 1: return n
    return fibonacci(n-1) + fibonacci(n-2)  # Two recursive calls — O(2ⁿ)

# O(n) time, O(1) space — modifies in place
def reverse_in_place(arr):
    lo, hi = 0, len(arr) - 1
    while lo < hi:
        arr[lo], arr[hi] = arr[hi], arr[lo]
        lo += 1; hi -= 1

# O(n) time, O(n) space — creates a new list
def reverse_copy(arr):
    return arr[::-1]

from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n):
    if n <= 1: return n
    return fib(n-1) + fib(n-2)
# Time: O(n) — each value computed once
# Space: O(n) — cache stores n values

def find_duplicates(arr):           # n = len(arr)
    seen = set()                    # O(1)
    duplicates = []
    for x in arr:                   # O(n) iterations
        if x in seen:               # O(1) per iteration (hash set)
            duplicates.append(x)    # O(1) amortised
        else:
            seen.add(x)             # O(1)
    return duplicates
# Total: O(n) time, O(n) space (the set)

# Contrast: naive O(n²) version
def find_duplicates_slow(arr):
    duplicates = []
    for i in range(len(arr)):       # O(n)
        for j in range(i+1, len(arr)):  # O(n)
            if arr[i] == arr[j] and arr[i] not in duplicates:
                duplicates.append(arr[i])
    return duplicates
# Total: O(n²) time, O(n) space (result list)
